import os
from vex_sdk import VexClient
from azure.ai.projects import AgentSession

vex = VexClient(api_key=os.getenv('VEX_API_KEY'))

def vex_middleware(agent_session: AgentSession, tool_call):
    policy_id = 'fintech-sox-tool-validation'
    validation = vex.validate_tool_call(
        session_id=agent_session.session_id,
        tool_call=tool_call,
        policy_id=policy_id,
        context={'industry': 'fintech', 'compliance': ['SOX', 'PCI']}
    )
    if not validation.approved:
        return {'error': validation.reason, 'action': 'BLOCK'}
    return agent_session.execute_tool(tool_call)

