import { VexClient } from '@vex-sdk/core';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

export async function azureAgentMiddleware(agentResponse: any) {
  const policyId = 'fintech-sec-disclaimer';

  const validation = await vex.validateResponse({
    sessionId: agentResponse.sessionId,
    content: agentResponse.content,
    policyId,
    context: { containsAdvice: /recommend|buy|sell/i.test(agentResponse.content) }
  });

  if (validation.approved) {
    agentResponse.content += '\n\n*SEC DISCLAIMER: Not personalized financial advice. Past performance doesn't guarantee future results.*';
  } else {
    throw new Error(`Blocked: ${validation.reason}`);
  }

  return agentResponse;
}

